const payload = $input.item.json.body || $input.item.json;

// Verificacao de dados criticos
const dadosCriticosPresentes = payload.escopo && payload.local && payload.clienteId;

if (!dadosCriticosPresentes) {
  return [{
    json: {
      status: "Sob Avaliação Técnica",
      mensagem: "Faltam dados críticos para precificação automática.",
      payloadOriginal: payload
    }
  }];
}

// Verifica se há gastronomia para urgência
let fatorUrgencia = 1.0;
const escopoStr = JSON.stringify(payload.escopo).toLowerCase();
if (escopoStr.includes('chapa') || escopoStr.includes('fritadeira') || escopoStr.includes('gastronomia')) {
  fatorUrgencia = 1.35; // Alta urgência
}

return [{
  json: {
    status: "Processando",
    payload: payload,
    fatorUrgencia: fatorUrgencia
  }
}];

const data = $input.item.json;
const fatorUrgencia = data.fatorUrgencia || 1.0;
const imposto_estimado_percentual = 0.15;
const margem = 0.40;

// O custo interno (data.custoMateriais + data.custoMaoDeObra) NUNCA deve ser exposto
const custoBase = data.custoMateriais + data.custoMaoDeObra;
const precoVendaBase = custoBase / (1 - margem - imposto_estimado_percentual);
const precoRecomendado = precoVendaBase * fatorUrgencia;

const faixaComercialMin = precoRecomendado * 0.90;
const faixaComercialMax = precoRecomendado * 1.15;

return [{
  json: {
    status: "Sucesso",
    faixaComercial: {
      min: faixaComercialMin,
      max: faixaComercialMax
    },
    precoRecomendado: precoRecomendado,
    imposto: "imposto_estimado_percentual (Pendente de validação contábil)",
    observacao: "Valores não incluem eventuais custos de Avaliação Técnica presencial."
  }
}];
